// Wrapper that re-exports the service wrapper's App class
// This ensures the idiomatic App constructor is available
// even if index.js is regenerated by napi build.

const nativeBinding = require("./index.js");

// Re-export everything from the native binding
module.exports = nativeBinding;

// Override App with the service wrapper's version (has a proper constructor)
try {
  const _service = require("./service");
  module.exports.App = _service.App;
} catch (e) {
  // service.js may not be available; native binding's App will be used
}
